// Parse incoming foreman update — supports Tally, Typeform, and direct JSON
const raw = $input.item.json.body || $input.item.json;

let jobSite = '', percentComplete = 0, blockers = '', photoUrl = '',
    foremanName = '', foremanNote = '', jobId = '', updateDate = '';

try {
  if (raw.fields && Array.isArray(raw.fields)) {
    const f = raw.fields;
    const find = (kw) => { const m = f.find(x => x.label && x.label.toLowerCase().includes(kw)); return m ? String(m.value || '') : ''; };
    jobSite = find('job') || find('site') || find('project');
    percentComplete = parseInt(find('percent') || find('complete') || find('progress') || '0');
    blockers = find('block') || find('issue');
    photoUrl = find('photo') || find('image');
    foremanName = find('foreman') || find('name');
    foremanNote = find('note') || find('update') || find('comment');
  } else {
    jobSite = raw.job_site || raw.jobSite || raw.project || '';
    percentComplete = parseInt(raw.percent_complete || raw.percentComplete || raw.progress || '0');
    blockers = raw.blockers || raw.blocker || '';
    photoUrl = raw.photo_url || raw.photoUrl || '';
    foremanName = raw.foreman_name || raw.foremanName || '';
    foremanNote = raw.foreman_note || raw.foremanNote || raw.note || raw.update || '';
  }
  jobId = raw.job_id || raw.jobId || 'JOB-UNKNOWN';
  updateDate = raw.update_date || new Date().toISOString().split('T')[0];
} catch(e) {
  jobSite = raw.job_site || '';
  percentComplete = parseInt(raw.percent_complete || '0');
  updateDate = new Date().toISOString().split('T')[0];
}

return [{ json: {
  job_id: jobId, job_site: jobSite, percent_complete: percentComplete,
  blockers: blockers, photo_url: photoUrl, foreman_name: foremanName,
  foreman_note: foremanNote, update_date: updateDate, received_at: new Date().toISOString()
}}];

// CANONICAL NODE — all downstream nodes reference $('Build Canonical Record')
const ai = (() => {
  try {
    const r = $('AI Classify Job').item.json;
    const c = (r.content && r.content[0]) ? r.content[0].text : '';
    const m = c.match(/\{[\s\S]*\}/);
    return JSON.parse(m ? m[0] : c);
  } catch(e) { return null; }
})();
const input = $('Parse Foreman Update').item.json;

const jobType = ai ? ai.job_type : 'unknown';
const status = ai ? ai.status : (input.blockers ? 'blocked' : 'on_track');
const statusColor = status === 'blocked' ? '🔴' : status === 'at_risk' ? '🟠' : '🟢';
const complianceFlags = (ai && ai.compliance_flags) ? ai.compliance_flags : [];
const permitAlert = ai ? ai.permit_alert : 'no';
const stalled = ai ? ai.stalled_detection : 'no';
const ownerAlertNeeded = status === 'blocked' || stalled === 'yes' || permitAlert === 'yes';

const subject = input.job_site + ' — ' + jobType.replace('_',' ').toUpperCase() + ' Update (' + input.percent_complete + '%)';
const body = '<h2>' + jobType.replace('_',' ').toUpperCase() + ' Update</h2><p><b>Project:</b> ' + input.job_site + '</p><p><b>Progress:</b> ' + input.percent_complete + '%</p><p><b>Status:</b> ' + statusColor + ' ' + status.toUpperCase() + '</p><hr><p>' + (ai ? ai.client_summary : 'Work is progressing.') + '</p><p><b>Next:</b> ' + (ai ? ai.next_milestone : 'TBD') + '</p>';

const alertSubject = (status==='blocked' ? '🔴 BLOCKED: ' : stalled==='yes' ? '🟠 STALLED: ' : '🔔 PERMIT: ') + input.job_site;
const alertBody = '<h2 style="color:' + (status==='blocked'?'red':'#e67e00') + ';">' + input.job_site + '</h2><p><b>Foreman:</b> ' + input.foreman_name + '</p><p><b>Status:</b> ' + statusColor + ' ' + status.toUpperCase() + '</p>' + (input.blockers ? '<p><b>Blocker:</b> ' + input.blockers + '</p>' : '') + '<p><b>Summary:</b> ' + (ai ? ai.foreman_summary : input.foreman_note) + '</p>';

return [{ json: {
  job_id: input.job_id, job_site: input.job_site, percent_complete: input.percent_complete,
  blockers: input.blockers, photo_url: input.photo_url, foreman_name: input.foreman_name,
  foreman_note: input.foreman_note, update_date: input.update_date,
  job_type: jobType, status: status, status_emoji: statusColor,
  compliance_flags: complianceFlags, permit_alert: permitAlert,
  stalled_detection: stalled, owner_alert_needed: ownerAlertNeeded,
  foreman_summary: ai ? ai.foreman_summary : input.foreman_note,
  client_summary: ai ? ai.client_summary : 'Work is progressing.',
  next_milestone: ai ? ai.next_milestone : 'TBD',
  risk_factors: (ai && ai.risk_factors) ? ai.risk_factors : (input.blockers ? [input.blockers] : []),
  client_email_subject: subject, client_email_body: body,
  owner_alert_subject: alertSubject, owner_alert_body: alertBody,
  processed_at: new Date().toISOString()
}}];

const d = $('Build Canonical Record').item.json;
const flags = d.compliance_flags || [];
if (flags.length === 0) return [];
return flags.map(f => ({ json: {
  'Date': d.update_date, 'Job ID': d.job_id,
  'Job Site': d.job_site, 'Job Type': d.job_type,
  'Compliance Flag': f, 'Status': d.status, 'Reported': 'Yes'
}}));

const d = $('Build New Job Record').item.json;
return [{ json: {
  'Job ID': d.job_id, 'Job Site': d.job_site, 'Job Type': d.job_type,
  'Client': d.client, 'Foreman': d.foreman, 'Contract Value': d.contract_value,
  'Start Date': d.start_date, 'Target End Date': d.target_end_date,
  'Permit Status': d.permit_status,
  'Permits Required': (d.permits_required||[]).join(', '),
  'Compliance Tags': (d.compliance_tags||[]).join(', '),
  'Reporting Cadence': d.reporting_cadence,
  'Client Email': d.client_email,
  'Vincent Alert': d.vincent_alert,
  'Current Status': 'on_track', 'Percent Complete': '0'
}}];

const d = $('Build Canonical Record').item.json;
return [{ json: {
  send_to: 'CONFIGURE-CLIENT-EMAIL',
  email_subject: d.client_email_subject,
  email_body: d.client_email_body
}}];

const d = $('Build Canonical Record').item.json;
return [{ json: {
  send_to: 'CONFIGURE-OWNER-EMAIL',
  email_subject: d.owner_alert_subject,
  email_body: d.owner_alert_body
}}];

const d = $('Build Canonical Record').item.json;
return [{ json: {
  success: true, job_id: d.job_id, job_site: d.job_site, job_type: d.job_type,
  percent_complete: d.percent_complete, status: d.status,
  status_emoji: d.status_emoji, stalled: d.stalled_detection === 'yes',
  permit_alert: d.permit_alert === 'yes',
  foreman_summary: d.foreman_summary, client_summary: d.client_summary,
  next_milestone: d.next_milestone,
  compliance_flags: d.compliance_flags,
  actions: ['AI classified: ' + d.status.toUpperCase() + '/' + d.job_type.toUpperCase(), 'Logged to Job Log', 'Client report sent', d.owner_alert_needed ? 'OWNER ALERTED' : 'No alert'],
  processed_at: d.processed_at
}}];

const d = $('Build New Job Record').item.json;
return [{ json: {
  success: true, job_id: d.job_id, job_site: d.job_site, job_type: d.job_type,
  compliance_tags: d.compliance_tags, permits_required: d.permits_required,
  reporting_cadence: d.reporting_cadence,
  actions: ['Added to Pipeline', d.vincent_alert==='yes'?'Vincent alerted':'No Vincent alert'],
  created_at: d.created_at
}}];
